sys_script_include.script:
/**
 * ITSMNotificationUtils
 * 
 * Description: Utility class for sending notifications related to incident lifecycle events.
 * Provides methods to send email notifications for incident creation, assignment,
 * state changes, and escalations.
 * 
 * Usage:
 *   var notif = new ITSMNotificationUtils();
 *   notif.sendIncidentCreatedNotification(gr);
 *   notif.sendStateChangeNotification(gr, previousState);
 */

var ITSMNotificationUtils = Class.create();
ITSMNotificationUtils.prototype = {
    initialize: function() {},

    /**
     * Send notification when a new incident is created
     * @param {GlideRecord} gr - The incident GlideRecord
     */
    sendIncidentCreatedNotification: function(gr) {
        if (!gr) return;

        // Trigger the "Incident Created" event
        gr.setEvent('incident.created', gr.getUniqueValue(), 
                    'Incident ' + gr.number + ' has been created');

        gs.info('ITSMNotificationUtils: Notification sent for new incident ' + gr.number);
    },

    /**
     * Send notification when an incident is assigned to a group
     * @param {GlideRecord} gr - The incident GlideRecord
     * @param {string} previousGroup - Previous assignment group sys_id
     */
    sendAssignedNotification: function(gr, previousGroup) {
        if (!gr) return;

        var currentGroup = gr.getValue('assignment_group');
        if (currentGroup && currentGroup !== previousGroup) {
            // Trigger the "Incident Assigned" event
            gr.setEvent('incident.assigned', gr.getUniqueValue(),
                        'Incident ' + gr.number + ' has been assigned to ' + 
                        gr.getDisplayValue('assignment_group'));

            gs.info('ITSMNotificationUtils: Assignment notification sent for incident ' + 
                     gr.number);
        }
    },

    /**
     * Send notification when incident state changes
     * @param {GlideRecord} gr - The incident GlideRecord
     * @param {number} previousState - Previous state value
     */
    sendStateChangeNotification: function(gr, previousState) {
        if (!gr) return;

        var currentState = gr.getValue('state');
        if (currentState !== previousState) {
            var stateLabel = this.getStateLabel(currentState);
            var prevLabel = this.getStateLabel(previousState);

            // Trigger the "Incident State Changed" event
            gr.setEvent('incident.state_changed', gr.getUniqueValue(),
                        'Incident ' + gr.number + ' state changed from "' + 
                        prevLabel + '" to "' + stateLabel + '"');

            gs.info('ITSMNotificationUtils: State change notification sent for incident ' + 
                     gr.number + ': ' + prevLabel + ' -> ' + stateLabel);
        }
    },

    /**
     * Send notification when incident is escalated to L2
     * @param {GlideRecord} gr - The incident GlideRecord
     */
    sendEscalationNotification: function(gr) {
        if (!gr) return;

        // Trigger the "Incident Escalated" event
        gr.setEvent('incident.escalated', gr.getUniqueValue(),
                    'Incident ' + gr.number + ' has been escalated to L2 Support Team');

        gs.info('ITSMNotificationUtils: Escalation notification sent for incident ' + 
                 gr.number);
    },

    /**
     * Get human-readable label for incident state value
     * @param {number} state - State integer value
     * @returns {string} - Human-readable state label
     */
    getStateLabel: function(state) {
        var stateMap = {
            1: 'New',
            2: 'In Progress',
            3: 'On Hold',
            6: 'Resolved',
            7: 'Closed'
        };
        return stateMap[state] || 'Unknown (' + state + ')';
    },

    type: 'ITSMNotificationUtils'
};
